
#pagination{
  .post-comment-num{
    //border-top: 1px solid #e7edef;
    text-align: center;
    padding-top: 2px;
    padding-bottom: 7px;
    font-size: 12px;

    ul.pagination {
      display: inline-block;
      padding: 0;
      margin: 0;
    }

    ul.pagination li {

      display: inline;
    }

    ul.pagination li a {
      font-size: 12px;
      color: rgb(56, 56, 56);
      float: left;
      padding: 5px 11px;
      text-decoration: none;
      border-radius: 3px;
      cursor: pointer;
      box-sizing: border-box;

    }

    ul.pagination li a.active {
      background-color: rgba(58, 63, 81, .99);
      color: white;
      border-radius: 3px;
    }

    ul.pagination li a:hover:not(.active) {
      background-color: #ddd;
    }

    li.seatClz {
      a::selection {
        color: transparent !important;
        background-color: transparent !important;
      }

      a:hover {
        background-color: transparent !important;
      }

      a:hover {
        background-color: transparent !important;
      }

      a {
        cursor: default !important;
        color: transparent !important;
      }
    }

  }
}
